@app.post("/upload/csv")
async def upload_csv(file: UploadFile = File(...)):
    if not file.filename.lower().endswith(".csv"):
        raise HTTPException(status_code=400, detail="Only CSV files are allowed")
    upload_id = str(uuid.uuid4())
    target_dir = os.path.join(UPLOADS_DIR, upload_id)
    os.makedirs(target_dir, exist_ok=True)
    csv_path = os.path.join(target_dir, file.filename)
    with open(csv_path, "wb") as f:
        shutil.copyfileobj(file.file, f)
    save_upload_record(upload_id, file.filename, csv_path, "csv")
    return {"upload_id": upload_id, "path": csv_path}

@app.post("/upload/dataset-zip")
async def upload_dataset_zip(file: UploadFile = File(...)):
    if not file.filename.lower().endswith(".zip"):
        raise HTTPException(status_code=400, detail="Only ZIP files are allowed")
    upload_id = str(uuid.uuid4())
    target_dir = os.path.join(UPLOADS_DIR, upload_id)
    os.makedirs(target_dir, exist_ok=True)
    zip_path = os.path.join(target_dir, file.filename)
    with open(zip_path, "wb") as f:
        shutil.copyfileobj(file.file, f)
    extract_zip_to_dir(zip_path, target_dir)
    save_upload_record(upload_id, file.filename, zip_path, "zip")
    return {"upload_id": upload_id, "extracted_to": target_dir}

@app.post("/contribute")
async def contribute_example(
    file: UploadFile = File(...),
    label: str = Form(...)
):
    if not allowed_image_ext(file.filename):
        raise HTTPException(status_code=400, detail="Unsupported image type")
    safe_label = label.strip().replace("/", "_").replace("\\", "_")
    if not safe_label:
        raise HTTPException(status_code=400, detail="Label is required")

    contrib_id = str(uuid.uuid4())
    label_dir = os.path.join(CONTRIB_DIR, safe_label)
    os.makedirs(label_dir, exist_ok=True)
    ext = os.path.splitext(file.filename)[1].lower()
    image_path = os.path.join(label_dir, f"{contrib_id}{ext}")
    with open(image_path, "wb") as f:
        shutil.copyfileobj(file.file, f)

    save_contribution_record(contrib_id, image_path, safe_label)
    return {"contribution_id": contrib_id, "label": safe_label, "saved_path": image_path}

@app.post("/train")
def trigger_training(req: TrainRequest, background_tasks: BackgroundTasks):
    if training_state["running"]:
        raise HTTPException(status_code=409, detail="Training already in progress")
    job_id = str(uuid.uuid4())
    create_training_job(job_id)
    background_tasks.add_task(run_training_job, job_id, req)
    return {"job_id": job_id, "status": "queued"}

@app.get("/train/status")
def train_status():
    return training_state

@app.get("/train/jobs/{job_id}")
def get_job(job_id: str):
    conn = get_db()
    cur = conn.execute("SELECT id, status, message, metrics, created_at, updated_at FROM training_jobs WHERE id = ?", (job_id,))
    row = cur.fetchone()
    conn.close()
    if not row:
        raise HTTPException(status_code=404, detail="Job not found")
    metrics = json.loads(row[3]) if row[3] else None
    return {
        "id": row[0],
        "status": row[1],
        "message": row[2],
        "metrics": metrics,
        "created_at": row[4],
        "updated_at": row[5],
    }

@app.get("/model/info")
def model_info():
    if not os.path.exists(MODEL_PATH):
        return {"available": False}
    labels = []
    metadata = {}
    if os.path.exists(LABELS_PATH):
        with open(LABELS_PATH, "r", encoding="utf-8") as f:
            labels = json.load(f)
    if os.path.exists(META_PATH):
        with open(META_PATH, "r", encoding="utf-8") as f:
            metadata = json.load(f)
    return {"available": True, "labels": labels, "metadata": metadata}

@app.post("/predict")
async def predict(file: UploadFile = File(...)):
    if not os.path.exists(MODEL_PATH) or not os.path.exists(LABELS_PATH):
        raise HTTPException(status_code=404, detail="No trained model available")
    if not allowed_image_ext(file.filename):
        raise HTTPException(status_code=400, detail="Unsupported image type")

    model = tf.keras.models.load_model(MODEL_PATH)
    with open(LABELS_PATH, "r", encoding="utf-8") as f:
        labels = json.load(f)

    content = await file.read()
    img = Image.open(io.BytesIO(content)).convert("RGB")
    input_size = model.input_shape[1]
    img = img.resize((input_size, input_size))
    arr = np.asarray(img, dtype=np.float32) / 255.0
    arr = np.expand_dims(arr, axis=0)

    probs = model.predict(arr, verbose=0)[0]
    idx = int(np.argmax(probs))
    return {
        "predicted_label": labels[idx],
        "confidence": float(probs[idx]),
        "probabilities": {labels[i]: float(probs[i]) for i in range(len(labels))}
    }

@app.get("/dataset/stats")
def dataset_stats():
    samples = gather_training_samples()
    counts = {}
    for _, label in samples:
        counts[label] = counts.get(label, 0) + 1
    return {
        "total_samples": len(samples),
        "class_distribution": counts
    }

